const cfg = $('Workflow Configuration').first().json;
const staleDays = Number(cfg.staleDays || 14);
const maxRefresh = Number(cfg.maxRefreshPerRun || 30);
const now = Date.now();
const cutoff = now - (staleDays * 24 * 60 * 60 * 1000);
const rows = $input.all().map(item => item.json).filter(row => {
  const checked = row.last_checked_at ? Date.parse(row.last_checked_at) : 0;
  const dueRetry = String(row.pipeline_status || row.status || '').toUpperCase() === 'FAILED_RETRYABLE' && (!row.next_retry_at || Date.parse(row.next_retry_at) <= now);
  const leaseExpired = row.lease_until && Date.parse(row.lease_until) <= now;
  const missingEmail = !row.email && !row.contact_page && String(row.qualification_status || '').toLowerCase() === 'qualified';
  const failedSync = String(row.ghl_sync_status || '').toLowerCase() === 'failed';
  const stale = checked && checked < cutoff && ['DONE', 'ENRICHED'].includes(String(row.pipeline_status || row.status || '').toUpperCase());
  return dueRetry || leaseExpired || missingEmail || failedSync || stale;
}).slice(0, maxRefresh);
return rows.map(row => ({ json: row }));

const now = new Date().toISOString();
const slugify = value => String(value || '').toLowerCase().replace(/[^a-z0-9|]+/g, '-').replace(/^-+|-+$/g, '');
return $input.all().map(item => {
  const keyword = item.json.primary_keyword || item.json.matched_keywords?.split(',')[0] || 'med spa';
  const operationalKeyword = keyword === 'med spa near me' ? 'med spa' : keyword;
  const queryText = `${operationalKeyword} in ${item.json.city}, ${item.json.state}`;
  const searchJobId = slugify(`${item.json.city}|${item.json.state}|${keyword}|refresh|${item.json.lead_id || item.json.dedupe_key}|v1`);
  return {
    json: {
      search_job_id: searchJobId,
      queue_key: searchJobId,
      city: item.json.city,
      state: item.json.state,
      state_code: item.json.state_code || '',
      keyword,
      source_query_template: keyword,
      source_query_executed: queryText,
      query_text: queryText,
      status: 'READY',
      attempt_count: 0,
      max_attempts: Number(item.json.max_attempts || $('Workflow Configuration').first().json.maxAttempts || 3),
      last_run_at: '',
      next_retry_at: '',
      lease_owner: '',
      lease_until: '',
      apify_run_id: '',
      apify_dataset_id: '',
      result_count: '',
      last_error_code: '',
      last_error: '',
      created_at: now,
      updated_at: now,
      completed_at: '',
      schema_version: 'v1',
    }
  };
});
